import axios from "axios";

const BASE_URL = "http://localhost:8080";

// ================= AUTH =================
export const registerUser = (user) =>
  axios.post(`${BASE_URL}/auth/register`, user);

export const loginUser = (user) =>
  axios.post(`${BASE_URL}/auth/login`, user);

// ================= ITEMS (ADMIN) =================
export const getItems = () =>
  axios.get(`${BASE_URL}/admin/products`, {
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`
    }
  });

export const addItem = (item) =>
  axios.post(`${BASE_URL}/admin/products`, item, {
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`
    }
  });

export const updateItem = (id, item) =>
  axios.put(`${BASE_URL}/admin/products/${id}`, item, {
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`
    }
  });

export const deleteItem = (id) =>
  axios.delete(`${BASE_URL}/admin/products/${id}`, {
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`
    }
  });

// ================= ORDERS (ADMIN) =================
export const getOrders = () =>
  axios.get(`${BASE_URL}/admin/orders`, {
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`
    }
  });

export const updateOrderStatus = (id, status) =>
  axios.put(
    `${BASE_URL}/admin/orders/${id}/status?status=${status}`,
    {},
    {
      headers: {
        Authorization: `Bearer ${localStorage.getItem("token")}`
      }
    }
  );

// ================= USER CHECKOUT =================
export const placeOrder = (email) =>
  axios.post(`${BASE_URL}/orders/checkout?email=${email}`, {}, {
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`
    }
  });
